    array( 'text' => 'Donde dos o tres se reúnen en mi nombre, allí estoy yo en medio de ellos.',                         'ref' => 'Mt. 18:20' ),
    array( 'text' => 'El Señor, tu Dios, con su amor, a ti te renovará; se alegrará por ti con cánticos.',                'ref' => 'Sof. 3:17' ),
    array( 'text' => 'Escudriñad las Escrituras; porque a vosotros os parece que en ellas tenéis la vida eterna.',        'ref' => 'Jn. 5:39' ),
    array( 'text' => 'El que guarda su boca guarda su alma; mas el que mucho abre sus labios tendrá calamidad.',          'ref' => 'Prov. 13:3' ),
    array( 'text' => 'Honra a tu padre y a tu madre para que tus días se prolonguen.',                                    'ref' => 'Éx. 20:12' ),
    array( 'text' => 'En el principio creó Dios los cielos y la tierra.',                                                 'ref' => 'Gén. 1:1' ),
    array( 'text' => 'Y vio Dios todo lo que había hecho, y he aquí que era bueno en gran manera.',                       'ref' => 'Gén. 1:31' ),
    array( 'text' => 'Hágase tu voluntad, como en el cielo, así también en la tierra.',                                   'ref' => 'Mt. 6:10' ),
    array( 'text' => 'El pan nuestro de cada día, dánoslo hoy.',                                                          'ref' => 'Mt. 6:11' ),
    array( 'text' => 'Tuyo es el reino, el poder y la gloria, por todos los siglos.',                                     'ref' => 'Mt. 6:13' ),
    array( 'text' => 'Si perdonáis a los hombres sus ofensas, os perdonará también a vosotros vuestro Padre celestial.',  'ref' => 'Mt. 6:14' ),
    array( 'text' => 'El Señor te guardará; te guardará de todo mal; el Señor guardará tu salida y tu entrada.',          'ref' => 'Sal. 121:7-8' ),
    array( 'text' => 'No temas el terror nocturno, ni la saeta que vuele de día.',                                        'ref' => 'Sal. 91:5' ),
    array( 'text' => 'Pero yo y mi casa serviremos al Señor.',                                                            'ref' => 'Jos. 24:15' ),
    array( 'text' => 'Cuán bienaventurado el hombre que no anda en consejo de impíos.',                                   'ref' => 'Sal. 1:1' ),
    array( 'text' => 'Sino que en la ley del Señor está su deleite, y en su ley medita de día y de noche.',               'ref' => 'Sal. 1:2' ),
    array( 'text' => 'Será como árbol plantado junto a corrientes de aguas, que da su fruto en su tiempo.',               'ref' => 'Sal. 1:3' ),
    array( 'text' => 'Canten al Señor un cántico nuevo; canten al Señor, habitantes de toda la tierra.',                  'ref' => 'Sal. 96:1' ),
    array( 'text' => 'Grande es el Señor y muy digno de alabanza; más temible que todos los dioses.',                     'ref' => 'Sal. 96:4' ),
    array( 'text' => 'Alégrense en el Señor, y regocíjense, justos; y canten con júbilo todos los rectos de corazón.',   'ref' => 'Sal. 32:11' ),
    array( 'text' => 'El fruto de la justicia se siembra en paz para los que hacen la paz.',                              'ref' => 'Sant. 3:18' ),
    array( 'text' => 'Bienaventurado el hombre que soporta la tentación, porque cuando haya resistido, recibirá la corona de vida.', 'ref' => 'Sant. 1:12' ),
    array( 'text' => 'Toda buena dádiva y todo don perfecto desciende de lo alto, del Padre de las luces.',               'ref' => 'Sant. 1:17' ),
    array( 'text' => 'Sed hacedores de la palabra, y no tan solamente oidores.',                                          'ref' => 'Sant. 1:22' ),
    array( 'text' => 'Nada está oculto para Dios; todo está al descubierto ante aquel a quien debemos rendir cuentas.',   'ref' => 'Heb. 4:13' ),
    array( 'text' => 'Porque Dios es el que en vosotros produce así el querer como el hacer, por su buena voluntad.',     'ref' => 'Fil. 2:13' ),
    array( 'text' => 'Haced todo sin murmuraciones y contiendas.',                                                        'ref' => 'Fil. 2:14' ),
    array( 'text' => 'Sé humilde con todos. Sé paciente y soporta con amor a los demás.',                                 'ref' => 'Ef. 4:2' ),
    array( 'text' => 'Más bien, sean bondadosos y compasivos unos con otros, y perdónense.',                              'ref' => 'Ef. 4:32' ),
    array( 'text' => 'No pierdan la confianza, porque ella les reportará una gran recompensa.',                           'ref' => 'Heb. 10:35' ),

    // 211-240
    array( 'text' => 'Así que tenemos como firme y segura ancla del alma la esperanza.',                                  'ref' => 'Heb. 6:19' ),
    array( 'text' => 'Mantengamos firme la esperanza que profesamos, porque fiel es el que hizo la promesa.',             'ref' => 'Heb. 10:23' ),
    array( 'text' => 'Corramos con perseverancia la carrera que tenemos por delante.',                                    'ref' => 'Heb. 12:1' ),
    array( 'text' => 'Puestos los ojos en Jesús, el autor y consumador de la fe.',                                        'ref' => 'Heb. 12:2' ),
    array( 'text' => 'El Señor disciplina a los que ama.',                                                                'ref' => 'Heb. 12:6' ),
    array( 'text' => 'No se olviden de practicar la hospitalidad, pues gracias a ella algunos hospedaron ángeles.',       'ref' => 'Heb. 13:2' ),
    array( 'text' => 'El amor a los hermanos sea continuo.',                                                              'ref' => 'Heb. 13:1' ),
    array( 'text' => 'Contente con lo que tienes; porque él dijo: No te desampararé, ni te dejaré.',                      'ref' => 'Heb. 13:5' ),
    array( 'text' => 'El Señor es mi ayudador; no temeré lo que me pueda hacer el hombre.',                               'ref' => 'Heb. 13:6' ),
    array( 'text' => 'Al que puede hacer muchísimo más que todo lo que pedimos o imaginamos, a él sea la gloria.',         'ref' => 'Ef. 3:20-21' ),
    array( 'text' => 'Dios, que comenzó la buena obra en ustedes, la irá perfeccionando hasta el día de Cristo.',         'ref' => 'Fil. 1:6' ),
    array( 'text' => 'Para mí el vivir es Cristo y el morir es ganancia.',                                                'ref' => 'Fil. 1:21' ),
    array( 'text' => 'No hagan nada por egoísmo o vanidad; más bien, con humildad consideren a los demás.',               'ref' => 'Fil. 2:3' ),
    array( 'text' => 'Cada uno debe velar no solo por sus propios intereses, sino también por los intereses de los demás.', 'ref' => 'Fil. 2:4' ),
    array( 'text' => 'La actitud de ustedes debe ser como la de Cristo Jesús.',                                           'ref' => 'Fil. 2:5' ),
    array( 'text' => 'Regocíjense siempre en el Señor. Insisto: ¡Regocíjense!',                                          'ref' => 'Fil. 4:4' ),
    array( 'text' => 'Que su amabilidad sea evidente a todos. El Señor está cerca.',                                      'ref' => 'Fil. 4:5' ),
    array( 'text' => 'He aprendido a estar contento en cualquier estado en que me encuentre.',                            'ref' => 'Fil. 4:11' ),
    array( 'text' => 'Y la paz de Dios, que sobrepasa todo entendimiento, guardará sus corazones.',                       'ref' => 'Fil. 4:7' ),
    array( 'text' => 'Por lo demás, hermanos, piensen en todo lo verdadero y noble.',                                     'ref' => 'Fil. 4:8' ),
    array( 'text' => 'Mi Dios suplirá todo lo que les falta conforme a sus riquezas en gloria en Cristo Jesús.',          'ref' => 'Fil. 4:19' ),
    array( 'text' => 'Fortalecidos en todo sentido con el glorioso poder de Dios, para que tengan paciencia.',            'ref' => 'Col. 1:11' ),
    array( 'text' => 'Dando gracias al Padre que nos hizo aptos para participar de la herencia de los santos.',           'ref' => 'Col. 1:12' ),
    array( 'text' => 'Cristo en ustedes, la esperanza de gloria.',                                                        'ref' => 'Col. 1:27' ),
    array( 'text' => 'Como, pues, habéis recibido al Señor Jesucristo, andad en él.',                                     'ref' => 'Col. 2:6' ),
    array( 'text' => 'Si, pues, habéis resucitado con Cristo, buscad las cosas de arriba.',                               'ref' => 'Col. 3:1' ),
    array( 'text' => 'Revístanse de afecto entrañable y de bondad, humildad, amabilidad y paciencia.',                    'ref' => 'Col. 3:12' ),
    array( 'text' => 'Y sobre todas estas virtudes revístanse de amor, que es el vínculo perfecto.',                      'ref' => 'Col. 3:14' ),
    array( 'text' => 'Que la paz de Cristo gobierne en sus corazones.',                                                   'ref' => 'Col. 3:15' ),
    array( 'text' => 'La palabra de Cristo habite en abundancia en vosotros.',                                            'ref' => 'Col. 3:16' ),

    // 241-270
    array( 'text' => 'Todo lo que hagan, de palabra o de obra, háganlo en el nombre del Señor Jesús.',                   'ref' => 'Col. 3:17' ),
    array( 'text' => 'Perseveren en la oración, velando en ella con acción de gracias.',                                  'ref' => 'Col. 4:2' ),
    array( 'text' => 'Que su conversación sea siempre con gracia, sazonada con sal.',                                     'ref' => 'Col. 4:6' ),
    array( 'text' => 'Que Dios los haga crecer y abundar en amor unos para con otros y para con todos.',                  'ref' => '1 Tes. 3:12' ),
    array( 'text' => 'El Señor mismo descenderá del cielo con voz de mando, con voz de arcángel y con trompeta de Dios.', 'ref' => '1 Tes. 4:16' ),
    array( 'text' => 'Porque Dios no nos ha dado espíritu de timidez, sino de poder, de amor y de dominio propio.',       'ref' => '2 Tim. 1:7' ),
    array( 'text' => 'He peleado la buena batalla, he acabado la carrera, he guardado la fe.',                            'ref' => '2 Tim. 4:7' ),
    array( 'text' => 'Por lo demás, me está guardada la corona de justicia.',                                             'ref' => '2 Tim. 4:8' ),
    array( 'text' => 'La gracia de Dios se ha manifestado para salvación a todos los hombres.',                           'ref' => 'Tito 2:11' ),
    array( 'text' => 'El que comenzó tan buena obra en ustedes la irá perfeccionando.',                                   'ref' => 'Fil. 1:6' ),
    array( 'text' => 'Quiero conocer a Cristo; sí, quiero conocer el poder de su resurrección.',                          'ref' => 'Fil. 3:10' ),
    array( 'text' => 'Olvido lo que queda atrás y me esfuerzo por alcanzar lo que está delante.',                         'ref' => 'Fil. 3:13' ),
    array( 'text' => 'Sigo avanzando hacia la meta para ganar el premio que Dios ofrece en lo alto.',                     'ref' => 'Fil. 3:14' ),
    array( 'text' => 'Nuestra ciudadanía está en los cielos, de donde también esperamos al Salvador.',                    'ref' => 'Fil. 3:20' ),
    array( 'text' => 'Pedid y se os dará; buscad y hallaréis; llamad y se os abrirá.',                                   'ref' => 'Mt. 7:7' ),
    array( 'text' => 'Porque todo aquel que pide, recibe; y el que busca, halla.',                                        'ref' => 'Mt. 7:8' ),
    array( 'text' => 'Todo lo que quieran que los hombres hagan con ustedes, así también hagan con ellos.',               'ref' => 'Mt. 7:12' ),
    array( 'text' => 'El que hace la voluntad de mi Padre que está en los cielos, ese entrará en el reino de los cielos.', 'ref' => 'Mt. 7:21' ),
    array( 'text' => 'El que oye estas palabras mías y las practica, lo compararé a un hombre prudente.',                 'ref' => 'Mt. 7:24' ),
    array( 'text' => 'Lo que Dios ha unido, que no lo separe el hombre.',                                                 'ref' => 'Mr. 10:9' ),
    array( 'text' => 'Amarás al Señor tu Dios con todo tu corazón, con toda tu alma y con toda tu mente.',                'ref' => 'Mt. 22:37' ),
    array( 'text' => 'El segundo es semejante: Amarás a tu prójimo como a ti mismo.',                                     'ref' => 'Mt. 22:39' ),
    array( 'text' => 'Vayan por todo el mundo y anuncien las buenas nuevas a toda criatura.',                             'ref' => 'Mr. 16:15' ),
    array( 'text' => 'Yo estaré con ustedes siempre, hasta el fin del mundo.',                                            'ref' => 'Mt. 28:20' ),
    array( 'text' => 'Toda potestad me es dada en el cielo y en la tierra.',                                              'ref' => 'Mt. 28:18' ),
    array( 'text' => 'Vayan y hagan discípulos de todas las naciones.',                                                   'ref' => 'Mt. 28:19' ),
    array( 'text' => 'Espera en el Señor; esfuérzate, y aliéntese tu corazón; sí, espera en el Señor.',                  'ref' => 'Sal. 27:14' ),
    array( 'text' => 'El Señor saldrá como un guerrero; como hombre de guerra despertará su celo.',                       'ref' => 'Is. 42:13' ),
    array( 'text' => 'Aunque yo pase por el valle de la sombra de muerte, no temeré mal alguno.',                         'ref' => 'Sal. 23:4' ),
    array( 'text' => 'Tu vara y tu cayado me infunden aliento.',                                                          'ref' => 'Sal. 23:4' ),

    // 271-300
    array( 'text' => 'Me unges la cabeza con aceite; mi copa rebosa.',                                                    'ref' => 'Sal. 23:5' ),
    array( 'text' => 'Ciertamente el bien y la misericordia me seguirán todos los días de mi vida.',                      'ref' => 'Sal. 23:6' ),
    array( 'text' => 'En la casa del Señor moraré por largos días.',                                                      'ref' => 'Sal. 23:6' ),
    array( 'text' => 'El Señor es mi roca, mi amparo y mi libertador.',                                                   'ref' => 'Sal. 18:2' ),
    array( 'text' => 'A Dios clamo en mi angustia, y él me responde desde su monte santo.',                               'ref' => 'Sal. 3:4' ),
    array( 'text' => 'El Señor sostiene a todos los caídos y levanta a todos los oprimidos.',                             'ref' => 'Sal. 145:14' ),
    array( 'text' => 'El Señor es fiel a todas sus promesas y amoroso en todas sus obras.',                               'ref' => 'Sal. 145:13' ),
    array( 'text' => 'El Señor cuida a todos los que le aman, pero destruirá a todos los impíos.',                        'ref' => 'Sal. 145:20' ),
    array( 'text' => 'Alabe mi boca al Señor; que toda criatura alabe su santo nombre.',                                  'ref' => 'Sal. 145:21' ),
    array( 'text' => 'Con todo lo que soy, alabo al Señor. Alabaré al Señor mientras viva.',                              'ref' => 'Sal. 146:2' ),
    array( 'text' => 'El Señor reina eternamente; Sion, tu Dios reina por todas las generaciones.',                       'ref' => 'Sal. 146:10' ),
    array( 'text' => 'Él cuenta el número de las estrellas y les da nombre a cada una.',                                  'ref' => 'Sal. 147:4' ),
    array( 'text' => 'El Señor es grande y poderoso; su entendimiento no tiene límite.',                                  'ref' => 'Sal. 147:5' ),
    array( 'text' => 'El Señor se complace en los que le temen, en los que confían en su gran amor.',                     'ref' => 'Sal. 147:11' ),
    array( 'text' => 'Ha puesto sus palabras en la creación; rápida corre su palabra.',                                   'ref' => 'Sal. 147:15' ),
    array( 'text' => 'Alaben el nombre del Señor, porque solo su nombre es excelso.',                                     'ref' => 'Sal. 148:13' ),
    array( 'text' => 'Canten al Señor un cántico nuevo; alaben su nombre en la asamblea de los fieles.',                  'ref' => 'Sal. 149:1' ),
    array( 'text' => 'Porque el Señor se complace en su pueblo; a los humildes concede el honor de la victoria.',         'ref' => 'Sal. 149:4' ),
    array( 'text' => '¡Alaben a Dios en su santuario! ¡Alábenlo en su poderoso firmamento!',                             'ref' => 'Sal. 150:1' ),
    array( 'text' => 'Que todo lo que respira alabe al Señor.',                                                           'ref' => 'Sal. 150:6' ),
    array( 'text' => 'Así dice el Señor: No es por la fuerza ni por el poder, sino por mi Espíritu.',                    'ref' => 'Zac. 4:6' ),
    array( 'text' => 'El Señor de los ejércitos está con nosotros; el Dios de Jacob es nuestro refugio.',                 'ref' => 'Sal. 46:7' ),
    array( 'text' => 'Quédense quietos y reconozcan que yo soy Dios.',                                                    'ref' => 'Sal. 46:10' ),
    array( 'text' => 'El corazón alegre es una buena medicina, pero el espíritu abatido seca los huesos.',                'ref' => 'Prov. 17:22' ),
    array( 'text' => 'Mejor es un plato de verduras con amor que un buey gordo con odio.',                                'ref' => 'Prov. 15:17' ),
    array( 'text' => 'La respuesta amable calma la ira, pero la respuesta grosera la enciende.',                         'ref' => 'Prov. 15:1' ),
    array( 'text' => 'El perezoso dice: Hay un león en el camino. El pigre dice: Hay un león en las calles.',            'ref' => 'Prov. 26:13' ),
    array( 'text' => 'Como ciudad sin defensa y sin muralla es quien no sabe dominarse.',                                  'ref' => 'Prov. 25:28' ),
    array( 'text' => 'El que no recoge conmigo, desparrama.',                                                             'ref' => 'Mt. 12:30' ),
    array( 'text' => 'Nadie puede servir a dos señores.',                                                                 'ref' => 'Mt. 6:24' ),

    // 301-330
    array( 'text' => 'Así que no se afanen por el mañana; el mañana se afanará por sí mismo.',                           'ref' => 'Mt. 6:34' ),
    array( 'text' => 'Hay más dicha en dar que en recibir.',                                                              'ref' => 'Hch. 20:35' ),
    array( 'text' => 'La fe sin obras está muerta.',                                                                      'ref' => 'Sant. 2:26' ),
    array( 'text' => 'Humíllense delante del Señor, y él los exaltará.',                                                  'ref' => 'Sant. 4:10' ),
    array( 'text' => 'Dios se opone a los orgullosos, pero da gracia a los humildes.',                                    'ref' => 'Sant. 4:6' ),
    array( 'text' => 'Ante el Señor un día es como mil años, y mil años como un día.',                                    'ref' => '2 Ped. 3:8' ),
    array( 'text' => 'El Señor no tarda en cumplir su promesa, como algunos lo entienden.',                               'ref' => '2 Ped. 3:9' ),
    array( 'text' => 'Santifícalos en la verdad; tu palabra es la verdad.',                                               'ref' => 'Jn. 17:17' ),
    array( 'text' => 'Como el Padre me envió, también yo los envío.',                                                     'ref' => 'Jn. 20:21' ),
    array( 'text' => 'Reciban el Espíritu Santo.',                                                                        'ref' => 'Jn. 20:22' ),
    array( 'text' => 'Mi señor y mi Dios.',                                                                               'ref' => 'Jn. 20:28' ),
    array( 'text' => 'Dichosos los que no han visto y sin embargo creen.',                                                'ref' => 'Jn. 20:29' ),
    array( 'text' => 'Apacienta mis ovejas.',                                                                             'ref' => 'Jn. 21:17' ),
    array( 'text' => 'Siglos de los siglos a nuestro Dios le pertenecen el poder y la gloria.',                          'ref' => 'Ap. 7:12' ),
    array( 'text' => 'He aquí yo estoy a la puerta y llamo; si alguno oye mi voz y abre la puerta, entraré.',            'ref' => 'Ap. 3:20' ),
    array( 'text' => 'Al que salga vencedor le daré el derecho de sentarse conmigo en mi trono.',                        'ref' => 'Ap. 3:21' ),
    array( 'text' => 'No tengas miedo; yo soy el Primero y el Último.',                                                   'ref' => 'Ap. 1:17' ),
    array( 'text' => 'Él enjugará toda lágrima de sus ojos. Ya no habrá muerte, ni llanto, ni lamento ni dolor.',        'ref' => 'Ap. 21:4' ),
    array( 'text' => 'He aquí, yo hago nuevas todas las cosas.',                                                          'ref' => 'Ap. 21:5' ),
    array( 'text' => 'Yo soy el Alfa y la Omega, el principio y el fin.',                                                 'ref' => 'Ap. 21:6' ),
    array( 'text' => 'Espíritu y la Esposa dicen: ¡Ven! Y el que tiene sed, venga.',                                     'ref' => 'Ap. 22:17' ),
    array( 'text' => 'Sí, vengo en breve. Amén; sí, ven, Señor Jesús.',                                                  'ref' => 'Ap. 22:20' ),
    array( 'text' => 'Bendita tú entre las mujeres, y bendito el fruto de tu vientre.',                                  'ref' => 'Lc. 1:42' ),
    array( 'text' => 'Mi alma glorifica al Señor y mi espíritu se regocija en Dios mi Salvador.',                        'ref' => 'Lc. 1:46-47' ),
    array( 'text' => 'Porque el Altísimo es el Señor de toda la tierra.',                                                'ref' => 'Sal. 47:2' ),
    array( 'text' => 'Dios reina sobre las naciones; Dios está sentado en su santo trono.',                              'ref' => 'Sal. 47:8' ),
    array( 'text' => 'La tierra es del Señor y todo lo que hay en ella.',                                                 'ref' => 'Sal. 24:1' ),
    array( 'text' => '¿Quién puede subir al monte del Señor? Solo el de manos limpias y corazón puro.',                  'ref' => 'Sal. 24:3-4' ),
    array( 'text' => 'El Señor fuerte y poderoso, el Señor poderoso en batalla.',                                        'ref' => 'Sal. 24:8' ),
    array( 'text' => 'El Señor de los ejércitos; él es el Rey de la gloria.',                                            'ref' => 'Sal. 24:10' ),

    // 331-365
    array( 'text' => 'Dichoso el pueblo cuyo Dios es el Señor.',                                                          'ref' => 'Sal. 33:12' ),
    array( 'text' => 'Los ojos del Señor están sobre los justos, y sus oídos atentos a sus oraciones.',                  'ref' => 'Sal. 34:15' ),
    array( 'text' => 'El Señor libera a sus siervos; no serán condenados los que en él confían.',                        'ref' => 'Sal. 34:22' ),
    array( 'text' => 'El hombre bueno saca cosas buenas del buen tesoro de su corazón.',                                  'ref' => 'Lc. 6:45' ),
    array( 'text' => 'Ama a tus enemigos, haz bien a los que te odian.',                                                  'ref' => 'Lc. 6:27' ),
    array( 'text' => 'Traten a los demás como quieren que ellos los traten a ustedes.',                                   'ref' => 'Lc. 6:31' ),
    array( 'text' => 'Sean misericordiosos, así como su Padre es misericordioso.',                                        'ref' => 'Lc. 6:36' ),
    array( 'text' => 'Den y se les dará; se les echará en el regazo una medida buena, apretada y desbordante.',          'ref' => 'Lc. 6:38' ),
    array( 'text' => 'El que pierda su vida por mi causa, la encontrará.',                                                'ref' => 'Mt. 10:39' ),
    array( 'text' => 'No temas a los que matan el cuerpo pero no pueden matar el alma.',                                  'ref' => 'Mt. 10:28' ),
    array( 'text' => 'Los cabellos de su cabeza están todos contados.',                                                   'ref' => 'Mt. 10:30' ),
    array( 'text' => 'Busquen y encontrarán; llamen y se les abrirá.',                                                    'ref' => 'Lc. 11:9' ),
    array( 'text' => '¿Acaso no vale mucho más ustedes que las aves?',                                                    'ref' => 'Mt. 6:26' ),
    array( 'text' => 'Sean perfectos, como su Padre celestial es perfecto.',                                              'ref' => 'Mt. 5:48' ),
    array( 'text' => 'Que brille su luz ante los hombres, para que vean sus buenas obras.',                               'ref' => 'Mt. 5:16' ),
    array( 'text' => 'La ley y los profetas se resumen en esto: ama a Dios y ama a tu prójimo.',                         'ref' => 'Mt. 22:40' ),
    array( 'text' => 'Porque muchos son llamados, pero pocos los escogidos.',                                             'ref' => 'Mt. 22:14' ),
    array( 'text' => 'Dios, crea en mí un corazón puro y renueva la firmeza de mi espíritu.',                            'ref' => 'Sal. 51:10' ),
    array( 'text' => 'Devuélveme la alegría de tu salvación; que un espíritu obediente me sostenga.',                    'ref' => 'Sal. 51:12' ),
    array( 'text' => 'El sacrificio que te agrada es un espíritu quebrantado; tú, oh Dios, no desprecias el corazón quebrantado.', 'ref' => 'Sal. 51:17' ),
    array( 'text' => 'Porque tú, Señor, eres bueno y perdonador, grande en amor para todos los que te invocan.',         'ref' => 'Sal. 86:5' ),
    array( 'text' => 'Enséñame, Señor, tu camino para conducirme en tu verdad.',                                         'ref' => 'Sal. 86:11' ),
    array( 'text' => 'El Señor dice: Yo te instruiré y te enseñaré el camino que debes seguir.',                         'ref' => 'Sal. 32:8' ),
    array( 'text' => 'Muchas son las calamidades del malvado, pero el amor del Señor rodea al que en él confía.',        'ref' => 'Sal. 32:10' ),
    array( 'text' => 'Sobre nosotros, Señor, que recaiga tu amor, así como en ti hemos puesto nuestra esperanza.',       'ref' => 'Sal. 33:22' ),
